class PIIMaskingHelper:
    """Helper to mask PII data for logging purposes."""

    @staticmethod
    def mask_email(email: str) -> str:
        if not email or "@" not in email:
            return "***"
        local, domain = email.split("@", 1)
        if len(local) <= 2:
            masked_local = "*" * len(local)
        else:
            masked_local = local[0] + "*" * (len(local) - 2) + local[-1]
        return f"{masked_local}@{domain}"

    @staticmethod
    def mask_phone(phone: str) -> str:
        if not phone:
            return "***"
        digits = "".join(c for c in phone if c.isdigit())
        if len(digits) <= 4:
            return "***"
        return "*" * (len(digits) - 4) + digits[-4:]

    @staticmethod
    def mask_address(address: str) -> str:
        if not address:
            return "***"
        parts = address.split(",")
        if len(parts) > 1:
            return "***," + ",".join(parts[-2:])
        return "***"

    @classmethod
    def mask_user_data(cls, user_data: dict) -> dict:
        masked = user_data.copy()
        if "email" in masked:
            masked["email"] = cls.mask_email(masked["email"])
        if "phone_number" in masked:
            masked["phone_number"] = cls.mask_phone(masked["phone_number"])
        if "address" in masked:
            if isinstance(masked["address"], dict):
                masked["address"] = {k: "***" for k in masked["address"]}
            else:
                masked["address"] = cls.mask_address(str(masked["address"]))
        if "ssn" in masked:
            masked["ssn"] = "***-**-" + masked["ssn"][-4:] if len(masked["ssn"]) >= 4 else "***"
        if "date_of_birth" in masked:
            masked["date_of_birth"] = "****-**-**"
        return masked


